@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products..."
           @oninput="OnSearchInput"
           class="product-search-input" />

    @if (_isLoading)
    {
        <div class="product-search-status">Searching...</div>
    }
    else if (_error is not null)
    {
        <div class="product-search-error">Something went wrong. Please try again.</div>
    }
    else if (_hasSearched && _results.Count == 0)
    {
        <div class="product-search-status">No products found.</div>
    }

    @if (_results.Count > 0)
    {
        <div class="product-search-results">
            @foreach (var product in _results)
            {
                <div class="product-card" @onclick="() => SelectProduct(product)">
                    <img src="@product.ImageUrl" alt="@product.Name" class="product-card-image" />
                    <div class="product-card-body">
                        <h4 class="product-card-name">@product.Name</h4>
                        <p class="product-card-price">@product.Price.ToString("C")</p>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<Product> _results = new();
    private bool _isLoading;
    private bool _hasSearched;
    private string? _error;

    private Timer? _debounceTimer;
    private CancellationTokenSource? _searchCts;

    private void OnSearchInput(ChangeEventArgs e)
    {
        var query = e.Value?.ToString() ?? string.Empty;

        _debounceTimer?.Dispose();
        _debounceTimer = new Timer(
            _ => InvokeAsync(() => ExecuteSearch(query)),
            null,
            300,
            Timeout.Infinite);
    }

    private async Task ExecuteSearch(string query)
    {
        // Cancel any in-flight search
        _searchCts?.Cancel();
        _searchCts?.Dispose();
        _searchCts = new CancellationTokenSource();
        var ct = _searchCts.Token;

        if (string.IsNullOrWhiteSpace(query))
        {
            _results = new();
            _hasSearched = false;
            _isLoading = false;
            _error = null;
            StateHasChanged();
            return;
        }

        _isLoading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var results = await ProductService.SearchAsync(query, ct);
            if (ct.IsCancellationRequested) return;

            _results = results;
            _hasSearched = true;
        }
        catch (OperationCanceledException)
        {
            return;
        }
        catch (Exception)
        {
            _results = new();
            _error = "search_failed";
        }
        finally
        {
            if (!ct.IsCancellationRequested)
            {
                _isLoading = false;
                StateHasChanged();
            }
        }
    }

    private async Task SelectProduct(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    public void Dispose()
    {
        _debounceTimer?.Dispose();
        _searchCts?.Cancel();
        _searchCts?.Dispose();
    }
}

